import { takaro, data } from '@takaro/helpers';

async function main() {
  const { pog, gameServerId, module: mod, player } = data;

  const prefix = (await takaro.settings.settingsControllerGetOne('commandPrefix', gameServerId)).data.data.value;

  const existing = await takaro.variable.variableControllerSearch({
    search: { key: ['dn'] },
    filters: {
      gameServerId: [gameServerId],
      playerId: [pog.playerId],
      moduleId: [mod.moduleId],
    },
  });

  // The client-side command is a toggle; fire it either way.
  await takaro.gameserver.gameServerControllerExecuteCommand(gameServerId, {
    command: `eoc EOS_${pog.gameId} "showhits damage"`,
  });

  if (existing.data.data.length > 0) {
    // Was ON -> now OFF: remove the marker variable so it will NOT re-apply on connect.
    await takaro.variable.variableControllerDelete(existing.data.data[0].id);
    await player.pm('Damage numbers: OFF');
  } else {
    // Was OFF -> now ON: store the marker variable so it re-applies on connect.
    await takaro.variable.variableControllerCreate({
      key: 'dn',
      value: 'on',
      gameServerId,
      moduleId: mod.moduleId,
      playerId: pog.playerId,
    });
    await player.pm(`Damage numbers: ON. Run ${prefix}dn again to turn them off.`);
  }
}

await main();

