import { takaro, data } from '@takaro/helpers';

async function main() {
  const { pog, gameServerId, module: mod } = data;
  if (!pog) return;

  // Only re-apply for players who have enabled damage numbers.
  const existing = await takaro.variable.variableControllerSearch({
    search: { key: ['dn'] },
    filters: {
      gameServerId: [gameServerId],
      playerId: [pog.playerId],
      moduleId: [mod.moduleId],
    },
  });
  if (existing.data.data.length === 0) return;

  // Timing is handled by the hook's native 30s delay (set in the install config).
  await takaro.gameserver.gameServerControllerExecuteCommand(gameServerId, {
    command: `eoc EOS_${pog.gameId} "showhits damage"`,
  });
}

await main();
